  ('judicial-6a749408-moex-00081', 'judicial-6a749408', 'judicial-6a749408-moex-111-3d2b73b6', 'sub-judicial-6a749408-07', NULL, 'single_choice', '依民法之規定，總會決議之內容違反法令或章程，其效力為何？', '["無效", "無效，但不得以其無效對抗善意之第三人", "須經主管機關、檢察官或利害關係人向法院聲請，以宣告其行為為無效", "社員得於決議後3個月內請求法院撤銷其決議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:10+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "103", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理測驗員"}'::jsonb, NULL),
  ('judicial-6a749408-moex-00082', 'judicial-6a749408', 'judicial-6a749408-moex-111-3d2b73b6', 'sub-judicial-6a749408-07', NULL, 'single_choice', '甲將自己的A車以60萬元賣給乙，雙方約定下個月初交車及付款。不料，於交車前數日，A車於公共停 車場中遭雷電擊中而燒毀。依民法規定，下列敘述何者錯誤？', '["甲對乙免給付義務", "乙對甲免支付價金", "甲應對乙負債務不履行的損害賠償責任", "乙不得向甲請求給付A車"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:10+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "103", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理測驗員"}'::jsonb, NULL),
  ('judicial-6a749408-moex-00083', 'judicial-6a749408', 'judicial-6a749408-moex-111-3d2b73b6', 'sub-judicial-6a749408-07', NULL, 'single_choice', '甲任職於市政府警察局某分局派出所所長，因處理群眾陳抗事件，派出所人手不足，甲發現派出所內約聘 擔任庶務工作的事務工友乙因喜愛健身而身強體壯，遂拿一套警察制服給乙穿著，並命令乙與其他警員一 同至陳抗現場維持秩序。下列敘述何者正確？', '["乙進行群眾驅離，係依法令之行為，阻卻違法", "乙行使警察職權，係依所屬上級公務員之命令，阻卻違法", "乙依刑法第10條第2項規定，為公務員", "乙犯刑法第158條、第159條之冒充公務員行使職權罪與冒用公務員服章官銜罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:10+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "103", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理測驗員"}'::jsonb, NULL),
  ('judicial-6a749408-moex-00084', 'judicial-6a749408', 'judicial-6a749408-moex-111-3d2b73b6', 'sub-judicial-6a749408-07', NULL, 'single_choice', '性別工作平等法中有關「性騷擾」之規定，下列敘述何者錯誤？', '["求職者於求職時，雇主以具有性意味之言詞或行為，對其造成冒犯，致侵犯其人格尊嚴，該當性別工作 平等法所定義之性騷擾", "求職者於求職時，雇主對求職者為明示之性要求，作為勞務契約成立之交換條件，該當性別工作平等法 所定義之性騷擾", "受僱者於執行職務時，客戶以具有性別歧視之言詞或行為，對其造成敵意性之工作環境，致影響其工作 表現，該當性別工作平等法所定義之性騷擾", "受僱者於執行職務時，其同事以具有性意味之言詞或行為，對其造成冒犯性之工作環境，致侵犯其人格 尊嚴，該當性別工作平等法所定義之性騷擾"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:10+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "103", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理測驗員"}'::jsonb, NULL),
